const items = $input.all();
const results = [];
const agents = ['Cyrus', 'Maven', 'Orion', 'Atlas', 'Nova', 'Vega'];
const now = new Date();
const twelveHoursAgo = new Date(now.getTime() - 12 * 60 * 60 * 1000);

for (const item of items) {
  const clientId = item.json.id;
  const agentStatuses = [];

  for (const agent of agents) {
    // Check last activity for each agent
    const activity = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://bfzdcyuyilesubtgbhdc.supabase.co/rest/v1/agent_activity?client_id=eq.${clientId}&agent_name=eq.${agent}&order=created_at.desc&limit=1&select=id,agent_name,action,created_at`,
      headers: {
        'apikey': $env.SUPABASE_API_KEY,
        'Authorization': `Bearer ${$env.SUPABASE_API_KEY}`
      }
    });

    const lastActivity = activity && activity.length > 0 ? activity[0] : null;
    const isHealthy = lastActivity 
      ? new Date(lastActivity.created_at) > twelveHoursAgo 
      : false;

    agentStatuses.push({
      agent_name: agent,
      status: isHealthy ? 'healthy' : 'inactive',
      last_seen: lastActivity ? lastActivity.created_at : null,
      last_action: lastActivity ? lastActivity.action : null
    });
  }

  const healthyCount = agentStatuses.filter(a => a.status === 'healthy').length;
  const inactiveAgents = agentStatuses.filter(a => a.status === 'inactive').map(a => a.agent_name);

  results.push({
    json: {
      client_id: clientId,
      agents_checked: agents.length,
      healthy_count: healthyCount,
      inactive_agents: inactiveAgents.join(', ') || 'none',
      all_healthy: healthyCount === agents.length
    }
  });
}

return results;
